    }

    // Helper methods

    fn format_duration(&self, d: Duration) -> String {
        let secs = d.as_secs();
        if secs < 60 {
            format!("{}s", secs)
        } else if secs < 3600 {
            format!("{}m {}s", secs / 60, secs % 60)
        } else {
            format!("{}h {}m", secs / 3600, (secs % 3600) / 60)
        }
    }

    fn format_latency(&self, d: Duration) -> String {
        let micros = d.as_micros();
        if micros < 1000 {
            format!("{}μs", micros)
        } else if micros < 1_000_000 {
            format!("{:.1}ms", micros as f64 / 1000.0)
        } else {
            format!("{:.2}s", micros as f64 / 1_000_000.0)
        }
    }

    fn format_bytes(&self, bytes: u64) -> String {
        const KB: u64 = 1024;
        const MB: u64 = KB * 1024;
        const GB: u64 = MB * 1024;

        if bytes < KB {
            format!("{} B", bytes)
        } else if bytes < MB {
            format!("{:.1} KB", bytes as f64 / KB as f64)
        } else if bytes < GB {
            format!("{:.1} MB", bytes as f64 / MB as f64)
        } else {
            format!("{:.2} GB", bytes as f64 / GB as f64)
        }
    }

    fn format_percentage(&self, part: u64, total: u64) -> String {
        if total == 0 {
            "N/A".to_string()
        } else {
            format!("{:.1}%", (part as f64 / total as f64) * 100.0)
        }
    }

    fn success_rate(&self, stats: &StatsSnapshot) -> f64 {
        if stats.total_requests == 0 {
            1.0
        } else {
            stats.successful_requests as f64 / stats.total_requests as f64
        }
    }

    fn render_plain(&self, stats: &StatsSnapshot, console: &FastMcpConsole) {
        console.print(&format!("=== Server Statistics ==="));
        console.print(&format!("Uptime: {}", self.format_duration(stats.uptime)));
        console.print(&format!("Requests: {} total, {} successful, {} failed",
            stats.total_requests, stats.successful_requests, stats.failed_requests));
        console.print(&format!("Latency: {} avg, {} max",
            self.format_latency(stats.avg_latency), self.format_latency(stats.max_latency)));
    }
}
